1	'use strict';
2	// Shared free-LLM helper with an ALWAYS-ON fallback chain so no GEO module ever dies on one provider's rate limit.
3	// Order = best free first: Groq (fastest, Llama-3.3-70B) -> NVIDIA NIM (same model, the standing fallback) ->
4	// Gemini 2.0 Flash (plain). Each falls through on 429/error/empty. askGeminiGrounded() adds REAL Google-grounded
5	// citations when Gemini's free grounding quota is available (graceful: returns null when exhausted).
6	const https = require('https');
7	
8	// Global token-bucket: cap LLM calls across ALL concurrent mints so worker concurrency never trips
9	// Groq's free ~100 req/min ceiling. Configurable via LLM_MAX_PER_MIN (0/blank = unlimited).
10	const _RL = { max: parseInt(process.env.LLM_MAX_PER_MIN || '90', 10), hits: [] };
11	function _rlWait() {
12	  if (!_RL.max || _RL.max <= 0) return Promise.resolve();
13	  return new Promise((res) => {
14	    const tick = () => {
15	      const now = Date.now();
16	      _RL.hits = _RL.hits.filter((t) => now - t < 60000);
17	      if (_RL.hits.length < _RL.max) { _RL.hits.push(now); res(); } else { setTimeout(tick, 200); }
18	    };
19	    tick();
20	  });
21	}
22	
23	async function _post(url, key, payload, timeout = 9000) {
24	  await _rlWait();
25	  return new Promise((resolve) => {
26	    const body = JSON.stringify(payload); const u = new URL(url);
27	    const req = https.request(u, { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + key }, timeout }, (r) => {
28	      let b = ''; r.on('data', d => b += d); r.on('end', () => resolve({ status: r.statusCode, body: b }));
29	    });
30	    req.on('error', () => resolve({ status: 0, body: '' })); req.on('timeout', () => { req.destroy(); resolve({ status: 0, body: '' }); });
31	    req.write(body); req.end();
32	  });
33	}
34	
35	function _providers(env) {
36	  const p = [];
37	  if (env.GROQ_API_KEY) p.push({ name: 'groq', url: 'https://api.groq.com/openai/v1/chat/completions', key: env.GROQ_API_KEY, model: 'llama-3.3-70b-versatile' });
38	  if (env.NIM_API_KEY) p.push({ name: 'nvidia-nim', url: 'https://integrate.api.nvidia.com/v1/chat/completions', key: env.NIM_API_KEY, model: 'meta/llama-3.3-70b-instruct' });
39	  if (env.DEEPSEEK_API_KEY) p.push({ name: 'deepseek', url: 'https://api.deepseek.com/chat/completions', key: env.DEEPSEEK_API_KEY, model: 'deepseek-chat' });
40	  if (env.PERPLEXITY_API_KEY) p.push({ name: 'perplexity', url: 'https://api.perplexity.ai/chat/completions', key: env.PERPLEXITY_API_KEY, model: 'sonar' });
41	  if (env.OPENAI_API_KEY) p.push({ name: 'openai', url: 'https://api.openai.com/v1/chat/completions', key: env.OPENAI_API_KEY, model: 'gpt-4o-mini' });
42	  // Zero-cost mode: keep only the free provider (Groq); Gemini free is added separately in askLLM.
43	  if (/^(1|true|yes|on)$/i.test(env.LLM_FREE_ONLY || '')) return p.filter((x) => x.name === 'groq');
44	  return p;
45	}
46	
47	async function _geminiPlain(prompt, key, temperature, maxTokens, timeout = 9000) {
48	  const r = await new Promise((resolve) => {
49	    const body = JSON.stringify({ contents: [{ parts: [{ text: prompt }] }], generationConfig: { temperature, maxOutputTokens: maxTokens } });
50	    const req = https.request('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite:generateContent?key=' + key, { method: 'POST', headers: { 'Content-Type': 'application/json' }, timeout }, (res) => { let b = ''; res.on('data', d => b += d); res.on('end', () => resolve({ status: res.statusCode, body: b })); });
51	    req.on('error', () => resolve({ status: 0, body: '' })); req.on('timeout', () => { req.destroy(); resolve({ status: 0, body: '' }); });
52	    req.write(body); req.end();
53	  });
54	  if (r.status !== 200) return '';
55	  try { const j = JSON.parse(r.body); return (j.candidates && j.candidates[0] && j.candidates[0].content && j.candidates[0].content.parts && j.candidates[0].content.parts[0] && j.candidates[0].content.parts[0].text) || ''; } catch (_e) { return ''; }
56	}
57	
58	// Primary text helper with full fallback chain. Returns { text, provider }.
59	async function askLLM(prompt, { temperature = 0.4, maxTokens = 400, json = false, seed = null } = {}, env = process.env) {
60	  for (const p of _providers(env)) {
61	    const payload = { model: p.model, messages: [{ role: 'user', content: prompt }], temperature, max_tokens: maxTokens };
62	    if (seed !== null && seed !== undefined) payload.seed = seed;
63	    if (json && p.name !== 'perplexity') payload.response_format = { type: 'json_object' };
64	    const r = await _post(p.url, p.key, payload);
65	    if (r.status === 200) { try { const t = JSON.parse(r.body).choices[0].message.content; if (t && t.trim()) return { text: t, provider: p.name }; } catch (_e) {} }
66	    // on 429/5xx/empty: fall through to next provider
67	  }
68	  if (env.GEMINI_API_KEY) { const t = await _geminiPlain(prompt, env.GEMINI_API_KEY, temperature, maxTokens); if (t) return { text: t, provider: 'gemini' }; }
69	  // Alibaba Qwen (DashScope, OpenAI-compatible) — PAID final fallover, last resort per founder hierarchy
70	  // (groq -> nim -> gemini -> qwen). Only billed when every free provider above has 429'd/failed.
71	  if (env.DASHSCOPE_API_KEY) {
72	    const _qbase = (env.DASHSCOPE_BASE_URL || 'https://ws-68b311bmgelxd5vz.ap-southeast-1.maas.aliyuncs.com/compatible-mode/v1').replace(/\/$/, '');
73	    const _qpayload = { model: env.QWEN_MODEL || 'qwen-plus', messages: [{ role: 'user', content: prompt }], temperature, max_tokens: maxTokens };
74	    if (json) _qpayload.response_format = { type: 'json_object' };
75	    try { const r = await _post(_qbase + '/chat/completions', env.DASHSCOPE_API_KEY, _qpayload);
76	      if (r.status === 200) { const t = JSON.parse(r.body).choices[0].message.content; if (t && t.trim()) return { text: t, provider: 'qwen' }; }
77	    } catch (_e) {}
78	  }
79	  return { text: '', provider: null };
80	}
81	
82	// P3.2b: REAL Google-grounded answer + the sources Google's AI actually cites. Graceful: null when quota exhausted.
83	async function askGeminiGrounded(prompt, env = process.env, timeout = 12000) {
84	  const key = env.GEMINI_API_KEY; if (!key) return null;
85	  const r = await new Promise((resolve) => {
86	    const body = JSON.stringify({ contents: [{ parts: [{ text: prompt }] }], tools: [{ google_search: {} }] });
87	    const req = https.request('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite:generateContent?key=' + key, { method: 'POST', headers: { 'Content-Type': 'application/json' }, timeout }, (res) => { let b = ''; res.on('data', d => b += d); res.on('end', () => resolve({ status: res.statusCode, body: b })); });
88	    req.on('error', () => resolve({ status: 0, body: '' })); req.on('timeout', () => { req.destroy(); resolve({ status: 0, body: '' }); });
89	    req.write(body); req.end();
90	  });
91	  if (r.status !== 200) return null; // 429 quota / error -> graceful null, caller falls back to askLLM
92	  try {
93	    const j = JSON.parse(r.body); const c = (j.candidates || [])[0] || {}; const gm = c.groundingMetadata || {};
94	    const text = (c.content && c.content.parts || []).map(p => p.text || '').join(' ');
95	    const sources = (gm.groundingChunks || []).map(x => x.web && ({ uri: x.web.uri, title: x.web.title })).filter(Boolean);
96	    return { text, sources, queries: gm.webSearchQueries || [] };
97	  } catch (_e) { return null; }
98	}
99	module.exports = { askLLM, askGeminiGrounded };
