86	async function llmVerifyPayload(p) {
87	  const binding = Object.keys((p && p.binding) || {});
88	  // Nothing attached: nothing to second-guess. Unassessed payloads are still checked when they carry a
89	  // knowledge-mode binding map (v22), since wrong-law-on-family is exactly what this verifier exists to catch;
90	  // V11 handles the plain unassessed case.
91	  if (!binding.length || (p.compliance_unassessed === true && p.render_mode !== 'knowledge')) {
92	    return { status: 'skipped', flags: [], checked_at: new Date().toISOString() };
93	  }
94	  let out;
95	  try {
96	    const { run } = require('../llm/router.js');
97	    const { system, prompt } = _prompt(p);
98	    const r = await run({ role: 'extract', system, prompt, json: true, temperature: 0, max_tokens: 700, lead_id: p.lead_id, scan_id: p.domain });
99	    if (!r || !r.ok || !r.text) return { status: 'unavailable', flags: [], error: (r && r.error) || 'no_response', checked_at: new Date().toISOString() };
100	    const txt = String(r.text).replace(/```json|```/g, '').trim();
101	    out = JSON.parse(txt.slice(txt.indexOf('{'), txt.lastIndexOf('}') + 1));
102	    out._provider = r.provider + '/' + r.model;
103	  } catch (e) {
104	    return { status: 'unavailable', flags: [], error: String(e && e.message || e).slice(0, 160), checked_at: new Date().toISOString() };
105	  }
106	  const flags = [];
107	  // E-249 (v22.12) — THE LLM MAY NOT OVERRULE OUR OWN REGISTRY ON A SECTOR'S CORE REGULATORS.
108	  // wrigleys.co.uk: correctly classified law-firms/solicitors, and the quorum leg flagged UK_SRA_COC,
109	  // UK_SRA_TRANSPARENCY, UK_MLR_2017 and UK_LEGAL_OMBUDSMAN as "law-firm sector mismatch". Those are THE FOUR
110	  // CORE REGULATORS OF A SOLICITORS' FIRM. The verifier rejected the SRA Code of Conduct for an SRA-regulated
111	  // firm and quarantined a perfect audit for it. wardhadaway: same, plus UK_ASA_CAP and UK_CMA — both of which
112	  // bind every UK advertiser and trader, law firms included.
113	  // This is the E-241 lesson again: a model is being allowed to veto a curated, deterministic fact it cannot
114	  // possibly know better than we do. A framework that IS the sector's own regulator is immune to a
115	  // sector-implausibility flag, on both the main leg and the quorum leg. Wrong-FAMILY flags still apply — a US
116	  // regulator on a UK firm is still catchable; only "this regulator doesn't fit this sector" is refused, and only
117	  // for the regulators we have curated as core to that sector.
118	  const SECTOR_CORE = {
119	    'law-firms': [/SRA/i, /LEGAL_OMBUDSMAN/i, /BSB|BAR_STANDARDS/i, /CLC_/i, /MLR/i, /LSB/i, /SOLICITORS/i],
120	    'accounting': [/ICAEW|ACCA|ICAS|CIMA/i, /FRC/i, /HMRC/i, /MLR/i],
121	    'healthcare': [/CQC/i, /GMC|GDC|NMC|GPHC/i, /MHRA/i, /HTA/i],
122	    'finance': [/FCA/i, /PRA/i, /FSMA/i, /MLR/i, /CONSUMER_DUTY/i],
123	    'real-estate': [/RICS/i, /PROPERTY_OMBUDSMAN|TPO/i, /ESTATE_AGENTS|EAA/i, /MLR/i],
124	    'hospitality': [/FSA|FOOD/i, /ATOL|ABTA/i, /LICENSING/i],
125	  };
126	  // Laws that bind EVERY commercial site in a jurisdiction regardless of sector: no sector-implausibility flag
127	  // may ever remove them. (UK_CMA on a law firm is not "implausible" — the DMCC Act binds all traders.)
128	  const SECTOR_AGNOSTIC = /GDPR|DPA_|PECR|COOKIE|EPRIVACY|EQUALITY|COMPANIES_ACT|CRA_|CONSUMER|DMCC|CMA|ASA|CAP_CODE|ACCESSIB|EAA_|DSA/i;
129	  const _secKey = String(p.detected_sector || p.sector || '').toLowerCase();
130	  const _coreRx = SECTOR_CORE[_secKey] || [];
131	  const _isSectorCore = (code) => {
132	    const c = String(code || '').toUpperCase();
133	    return _coreRx.some((rx) => rx.test(c)) || SECTOR_AGNOSTIC.test(c);
134	  };
135	  // Any reason that amounts to "this framework does not fit this sector".
136	  const _sectorDoubtRx = /sector.?(implausible|mismatch|inapplicab|irrelevan|specific)|not (the )?(primary|relevant|applicable|correct)? ?(conduct )?regulator|does not (apply|fit|bind)|wrong sector|implausible|not sector|regulator for/i;
137	
138	  // E-228: DETERMINISTIC NEXUS SAFETY NET. Even if a model still flags a registered-country-family framework for
139	  // "no nexus", drop that flag — registration IS the nexus (establishment limb). This makes the doctrine robust
140	  // to model drift and permanently closes the Qatar (registered_country) false-quarantine class.
141	  const _regFam = _registeredFamily(p);
142	  const _nexusDoubtRx = /no nexus|without nexus|lacks? nexus|no (establishment|evidence)|not established|no on.?page|no proof|unverified nexus|missing (nexus|evidence)/i;
143	  // Whitelist intersection: the model may only flag codes the engine actually attached.
144	  const flagged = Array.isArray(out.flagged_frameworks) ? out.flagged_frameworks : [];
145	  for (const f of flagged) {
146	    const code = String((f && f.code) || '').trim();
147	    const reason = String((f && f.reason) || '').slice(0, 80);
148	    const _bindLabel = String((p.binding || {})[code] || '');
149	    // Path A guard: a framework in the registered-country family, flagged only for missing nexus, is a correct
150	    // establishment attachment — never quarantine it.
151	    if (_regFam && FAMILY_OF(code) === _regFam && _nexusDoubtRx.test(reason)) continue;
152	    // E-241 (v22.10): GLOBAL-FAMILY GUARD. A GLOBAL framework (GOOGLE_EEAT and any non-jurisdictional standard)
153	    // binds EVERY website by definition — it has no jurisdiction and therefore cannot have a "wrong family" or a
154	    // "missing nexus". The cross-verifier was flagging GOOGLE_EEAT as "foreign family, no nexus evidence" and
155	    // quarantining otherwise-perfect audits (freeths, brownejacobson: classify 10/10, everything else clean).
156	    // A GLOBAL code is never flaggable on family/nexus grounds. Sector-implausibility is still catchable.
157	    if (FAMILY_OF(code) === 'GLOBAL' && (_nexusDoubtRx.test(reason) || /famil|jurisdic|foreign/i.test(reason))) continue;
158	    // E-249: the sector's OWN regulator (and any sector-agnostic law) can never be "sector-implausible".
159	    if (_isSectorCore(code) && _sectorDoubtRx.test(reason)) continue;
160	    // v22.3 flag policy: the cross-check exists to catch WRONG-FAMILY and WRONG-SECTOR attachments. Opinions
161	    // about bindingness, generality or enforcement style are the catalogue's domain (binding labels carry them)
162	    // and must never quarantine a correct stack. Drop those; keep everything family/sector-shaped; when in doubt
163	    // keep (fail-closed) — but never drop a flag whose code sits OUTSIDE the payload's own families.
164	    let _FAL = { GB: 'UK', GBR: 'UK', EN: 'UK', UAE: 'AE', USA: 'US', KSA: 'SA', SAU: 'SA' };
165	    try { _FAL = require('../compliance/registry/jurisdiction.js').FAMILY_ALIAS || _FAL; } catch (_e2) {}   // E-210: one alias map
166	    const _fams = new Set((((p.jurisdiction_families || {}).families) || []).map(x => _FAL[String(x).toUpperCase()] || String(x).toUpperCase()));
167	    const _inFam = _fams.size === 0 || _fams.has(FAMILY_OF(code)) || FAMILY_OF(code) === 'GLOBAL';
168	    const _styleOnly = /voluntar|not mandatory|industry code|professional code|guideline|only if member|membership|non.?binding|not universally|not a (law|statute|framework)|not sector-specific|general (corporate|consumer|data protection)? ?law|enforcement (agency|body)|applies (to|across) (all|any|every)|umbrella|broad(ly)? applicable/i.test(reason);
169	    if (binding.includes(code) && !(_styleOnly && _inFam)) flags.push({ code, reason });
170	  }
171	  // E-228: a SECTOR flag quarantines ONLY when the model asserts a CONFIDENT, DIFFERENT, real sector. On a thin
172	  // crawl the model often says "unknown"/"unclear"/same — that is absence of evidence, not evidence of a wrong
173	  // sector, and must not override a deterministic classification (the sultan/thin-crawl class). Fail-open on
174	  // "can't tell"; fail-closed only on a genuine disagreement.
175	  {
176	    const _sb = String(out.sector_should_be || '').toLowerCase().trim();
177	    const _det = String(p.detected_sector || '').toLowerCase().trim();
178	    const _uninformative = !_sb || /unknown|unclear|uncertain|cannot|can't|n\/a|none|unsure|insufficient/.test(_sb) || _sb === _det;
179	    if (out.sector_ok === false && !_uninformative) flags.push({ code: 'SECTOR', reason: ('llm says ' + _sb).slice(0, 80) });
180	  }
181	  if (out.families_ok === false && Array.isArray(out.wrong_families) && out.wrong_families.length) {
182	    // E-228: the registered-country family can never be a "wrong family" — a firm is bound by its own country's
183	    // law by registration. Strip it from the rejection list; only genuinely foreign families remain flaggable.
