244	  { provider: 'groq', model: 'llama-3.3-70b-versatile' },   // 100K TPD — backstop when the 8B stalls
245	];
246	const _GEMINI_FREE = [{ provider: 'gemini', model: 'gemini-2.5-flash-lite' }];   // ~1000 RPD free, live model
247	const DEFAULT_CHAIN = [
248	  ..._CF_FREE, ..._GROQ_FREE,
249	  ...(process.env.NIM_API_KEY ? [{ provider: 'nim', model: _NIM_MODEL }] : []),
250	  ..._GEMINI_FREE, ..._QWEN_STEP,
251	];
