253	// Smart routing by role. HIERARCHY: Cloudflare Workers AI (if token) -> Groq 8B -> Groq 70B -> NIM -> Gemini
254	// Flash-Lite -> Qwen (paid, last). Every free lane is a SEPARATE quota, so exhausting one rolls to the next
255	// instead of straight to deterministic.
256	const ROUTE_BY_ROLE = {
257	  extract:    [..._CF_FREE, ..._GROQ_FREE, ...(process.env.NIM_API_KEY ? [{ provider: 'nim', model: _NIM_MODEL }] : []), ..._GEMINI_FREE, ..._QWEN_STEP],
258	  synthesise: [..._CF_FREE, ..._GROQ_FREE, ...(process.env.NIM_API_KEY ? [{ provider: 'nim', model: _NIM_MODEL }] : []), ..._GEMINI_FREE, ..._QWEN_STEP],
