262	async function run(args) {
263	  const { system, prompt, max_tokens, temperature, json, lead_id, scan_id, role } = args;
264	  const chain = args.chain || ROUTE_BY_ROLE[role] || DEFAULT_CHAIN;
265	
266	  // Budget check: have we blown the daily cap?
267	  const remaining = checkBudgetRemaining();
268	  if (remaining !== null && remaining <= 0) {
269	    return { ok: false, error: 'budget_exhausted_for_today', text: '' };
270	  }
271	
272	  // Free providers (Cloudflare Workers AI, Groq) rate-limit hard on CONCURRENCY — a burst of simultaneous mints all
273	  // get HTTP 429 even though the daily VOLUME quota is nowhere near exhausted, and a 429 clears in ~1s. Without retry
274	  // a single 429 falls straight through the whole chain to empty -> source:fallback (measured ~50% under load). So we
275	  // retry each provider a few times with JITTERED exponential backoff; the jitter de-synchronises the burst so the
276	  // retries land in different time slices and most succeed. Paid/quota providers (gemini) get a single attempt.
277	  const _retryable = (e) => /_429_|_5\d\d_|timeout|fetch_|AbortError|capacity|overloaded/i.test(String(e || ''));
278	  const _sleep = (ms) => new Promise((res) => setTimeout(res, ms));
279	  const _callRaw = async (step) => {
280	    if (step.provider === 'cloudflare') return callCloudflare({ system, prompt, model: step.model, max_tokens, temperature, json });
281	    if (step.provider === 'groq') return callGroq({ system, prompt, model: step.model, max_tokens, temperature, json });
282	    if (step.provider === 'nim') return callNIM({ system, prompt, model: step.model, max_tokens, temperature, json });
283	    if (step.provider === 'gemini') return callGemini({ system, prompt, model: step.model, max_tokens, temperature });
284	    if (step.provider === 'anthropic') return callAnthropic({ system, prompt, model: step.model, max_tokens, temperature });
285	    if (step.provider === 'qwen') return callQwen({ system, prompt, model: step.model, max_tokens, temperature, json });
286	    return null;
287	  };
288	  // CONCURRENCY GATE: the free providers 429 on simultaneous requests (burst of CONC mints x several LLM calls each),
289	  // and retrying without limiting concurrency just re-collides. A process-global semaphore serialises LLM calls to a
290	  // small width so each request lands in its own slice and the daily-volume quota (not concurrency) is the only limit.
291	  const _callStep = async (step) => { await _llmAcquire(); try { return await _callRaw(step); } finally { _llmRelease(); } };
292	  let lastErr = null;
293	  for (const step of chain) {
294	    let r = null;
295	    const maxAttempts = step.provider === 'gemini' ? 1 : 3;
296	    for (let attempt = 0; attempt < maxAttempts; attempt++) {
297	      r = await _callStep(step);
298	      if (!r) break;
299	      if ((r.ok && r.text && String(r.text).trim()) || !_retryable(r.error) || attempt === maxAttempts - 1) break;
300	      await _sleep(400 + attempt * 700 + Math.floor(Math.random() * 800)); // jittered backoff: ~0.4-1.2s, 1.1-1.9s
301	    }
302	    if (!r) continue;
303	
304	    const cost = ledger({
305	      provider: step.provider, model: step.model,
306	      prompt_tokens: r.prompt_tokens || 0, completion_tokens: r.completion_tokens || 0,
307	      latency_ms: r.latency_ms || 0, ok: r.ok, error: r.error,
308	      lead_id, scan_id, role
309	    });
310	
311	    if (r.ok && r.text && String(r.text).trim()) {
312	      // Bump scanner_budget_state.spent_usd_micro
313	      bumpBudget(cost);
314	      return {
315	        ok: true, text: r.text, provider: step.provider, model: step.model,
316	        prompt_tokens: r.prompt_tokens || 0, completion_tokens: r.completion_tokens || 0,
317	        latency_ms: r.latency_ms || 0, cost_usd_micro: cost
318	      };
319	    }
320	    lastErr = r.error || 'no_text';
321	  }
322	  return { ok: false, error: lastErr || 'all_providers_failed', text: '' };
323	}
324	
325	function checkBudgetRemaining() {
326	  const raw = pg(`SELECT (daily_cap_usd_micro - spent_usd_micro) FROM scanner_budget_state WHERE workspace_id=1 AND bucket_day=CURRENT_DATE`);
327	  if (!raw) {
328	    pg(`INSERT INTO scanner_budget_state (workspace_id, bucket_day) VALUES (1, CURRENT_DATE) ON CONFLICT DO NOTHING`);
329	    return null;
330	  }
331	  return Number(raw);
332	}
333	function bumpBudget(cost) {
334	  if (!cost || cost <= 0) return;
335	  pg(`UPDATE scanner_budget_state SET spent_usd_micro = spent_usd_micro + ${cost} WHERE workspace_id=1 AND bucket_day=CURRENT_DATE`);
336	  // Insert row if first call today
337	  const exists = pg(`SELECT 1 FROM scanner_budget_state WHERE workspace_id=1 AND bucket_day=CURRENT_DATE`);
338	  if (!exists) pg(`INSERT INTO scanner_budget_state (workspace_id, bucket_day, spent_usd_micro) VALUES (1, CURRENT_DATE, ${cost}) ON CONFLICT DO NOTHING`);
339	}
340	
341	// CLI smoke test
342	if (require.main === module) {
343	  (async () => {
344	    const r = await run({
345	      role: 'extract',
346	      system: 'You return only the requested JSON. No prose.',
347	      prompt: 'Return JSON {"ok":true,"engine":"phase6"}.',
348	      max_tokens: 64, temperature: 0, json: true
349	    });
350	    console.log(JSON.stringify(r, null, 2));
351	  })().catch(e => { console.error(e); process.exit(1); });
352	}
353	
354	
355	// PREFLIGHT — A MISSING KEY MUST SHOUT, NOT SHRUG.
356	// GROQ_API_KEY and GEMINI_API_KEY were valid and working the whole time, and simply were not in the mint's
357	// environment. The router asked, got nothing, fell silently down the chain, and landed on the most rate-limited
358	// provider in the stack. Nothing anywhere said "you are running the audit engine on your reserve tank". That is the
359	// same class of failure as the Companies House key, the cookie collector and the adjudicator: it degraded silently
360	// and reported success. Every silent degradation in this engine has cost weeks. This one gets a klaxon.
361	function llmPreflight() {
362	  const have = {
363	    cloudflare: !!(process.env.CLOUDFLARE_API_TOKEN && process.env.CLOUDFLARE_ACCOUNT_ID),
364	    groq: !!process.env.GROQ_API_KEY,
365	    gemini: !!process.env.GEMINI_API_KEY,
366	    nim: !!process.env.NIM_API_KEY,
367	    qwen: !!process.env.DASHSCOPE_API_KEY,
368	  };
369	  const missing = Object.entries(have).filter(([, v]) => !v).map(([k]) => k);
370	  const present = Object.entries(have).filter(([, v]) => v).map(([k]) => k);
371	  if (!present.length) {
372	    console.error('[llm] *** NO LLM PROVIDER IS CONFIGURED *** every gated decision will fail, and an audit without '
373	      + 'llm_verify is rejected by the database. Set GROQ_API_KEY at minimum.');
374	  } else if (missing.length) {
375	    console.error('[llm] preflight: available = ' + present.join(', ') + ' | MISSING = ' + missing.join(', ')
376	      + '. The chain will fall through the missing ones on EVERY call, which wastes attempts and pushes load onto '
377	      + 'the scarcest provider. These keys are free: set them.');
378	  } else {
379	    console.error('[llm] preflight: all providers configured (' + present.join(', ') + ')');
380	  }
381	  return { have, missing, present };
382	}
383	
384	module.exports = {
385	  llmPreflight, run, ledger, ROUTE_BY_ROLE };
