1	'use strict';
2	// E-222 (v22.6) — THE LLM GATE. Every LLM decision in the audit engine flows through one scored loop:
3	//   attempt -> parse -> RUBRIC SCORE (0-10) -> pass at >= threshold (default 7) -> else retry with a
4	//   feedback message naming the exact deficiencies -> after max_attempts (default 3) DROP to the caller's
5	//   deterministic fallback. Fail-closed by design: a dropped gate never fabricates, it hands control back.
6	//
7	// Scoring philosophy (research-grounded, see docs/llm-gate-design.md):
8	//   - Rubric points are DETERMINISTIC checks wherever possible (schema validity, enum membership, verbatim
9	//     evidence anchoring, cross-signal agreement). Self-reported model confidence is never a rubric input:
10	//     verbalized confidence is systematically miscalibrated; agreement with independent signals is not.
11	//   - Retry feedback names the specific deficiency ("sub_sector 'x' is not a node of sector 'y'; choose from:
12	//     ..."), which is the Self-Refine/Reflexion finding: targeted critique improves structured accuracy,
13	//     generic "try again" does not. Three attempts is the documented point of diminishing returns.
14	//   - Token discipline: the original evidence block is sent once per attempt unchanged (provider-side prompt
15	//     caching applies), feedback adds only deficiency bullets, enums are injected as compact code lists.
16	//
17	// Contract:
18	//   gateLLM({ role, system, prompt, rubric, threshold=7, max_attempts=3, chain, max_tokens, temperature,
19	//             scan_id, lead_id, runFn })  ->
20	//   { ok, out, score, attempts, provider, deficiencies, history:[{score, provider, deficiencies}] }
21	// `rubric(parsed, rawText)` returns { score: 0-10, deficiencies: [string], hard_fail?: bool }.
22	// `runFn` overrides the router (tests). Router failure counts as a scored-0 attempt (chain already retries
23	// per-provider internally, so a hard unavailability is real).
24	
25	// E-224 (v22.6.1): UNIQUE ESCALATING RETRIES. Each attempt is a DIFFERENT protocol, not a re-roll:
26	//   Attempt 1 · BASELINE — the caller's prompt as written.
27	//   Attempt 2 · FORENSIC — deficiencies + an extraction protocol: locate the verbatim proving sentence FIRST,
28	//               derive the value ONLY from it, output null when no sentence proves a value. Never infer.
29	//   Attempt 3 · MAXIMUM RIGOR — field-by-field quote→derive→validate-against-allowed-list→output procedure,
30	//               "null over guess" made explicit, and the PREMIUM chain (paid Qwen first, then Gemini) so the
31	//               final attempt runs on the strongest available model. This is the closest engineering truth to
32	//               "the third retry ensures success": strongest model + strictest protocol + honest nulls; if even
33	//               that scores <7 the gate DROPS to the deterministic fallback rather than ship a guess.
34	const PROTOCOLS = {
35	  2: 'ESCALATION PROTOCOL (attempt 2 — forensic extraction): for EVERY field, first locate the exact verbatim sentence in the DOC that proves it. Derive the value ONLY from that sentence. If no sentence proves a value, output null for that field — never infer, never generalise, never use outside knowledge.',
36	  3: 'ESCALATION PROTOCOL (attempt 3 — maximum rigor, final): work field by field. Step 1: quote the shortest verbatim evidence span. Step 2: derive the value ONLY from that quote. Step 3: check the value against the allowed list in the schema; if it is not in the list, pick the closest allowed value ONLY if the quote clearly supports it, else null. Step 4: output. A null is a correct answer; a guess is a failure. Return the strict JSON only.',
37	};
38	async function gateLLM(opts) {
39	  const {
40	    role = 'extract', system, prompt, rubric, chain, premium_chain,
41	    max_tokens = 700, temperature = 0, scan_id, lead_id, runFn,
42	  } = opts || {};
43	  const threshold = Number.isFinite(+opts.threshold) ? +opts.threshold : 7;
44	  const maxAttempts = Math.max(1, Math.min(5, Number(opts.max_attempts || 3)));
45	  const deadlineMs = Number(opts.deadline_ms || 0);
46	  const t0 = Date.now();
47	  let run = runFn;
48	  if (!run) { try { run = require('./router.js').run; } catch (_e) { run = null; } }
49	  const history = [];
50	  let feedback = '';
51	  if (!run || typeof rubric !== 'function') {
52	    return { ok: false, out: null, score: 0, attempts: 0, provider: null, deficiencies: ['gate_unavailable'], history };
53	  }
54	  // THE ESCALATION LADDER. Attempts 1-2 use the router's ordinary chain (Cloudflare and Groq 8B first: free, fast,
55	  // 500K tokens a day). Attempt 3 is the HARD CASE, so it escalates to a STRONGER model - but "stronger" is not the
56	  // same as "scarcer", and this list had them confused.
57	  //
58	  // The old ladder put QWEN and GEMINI first. Gemini's free tier is roughly 1,000 REQUESTS A DAY. So every hard case
59	  // in the engine - and with a rubric threshold of 7, a great many cases are hard - spent the scarcest quota in the
60	  // whole stack, exhausted it, and then the gate failed. A failed gate means no llm_verify on the payload, and the
61	  // database (correctly) throws the audit away as a stub. That is how "we have plenty of LLM keys" ends in a lost
62	  // audit.
63	  //
64	  // The correct ladder escalates CAPABILITY while spending the CHEAPEST sufficient quota first:
65	  //   1. Groq 70B  - 100K tokens/day free, genuinely strong at structured JSON, and fast.
66	  //   2. Cloudflare 70B - free neuron budget, independent of Groq's quota, so an exhausted Groq does not block us.
67	  //   3. Gemini    - ~1,000 requests/day. Precious. It is the reserve, not the opening move.
68	  //   4. Qwen      - last, and only if a key exists.
69	  const _defaultPremium = [
70	    { provider: 'groq', model: 'llama-3.3-70b-versatile' },
71	    ...(process.env.CLOUDFLARE_API_TOKEN && process.env.CLOUDFLARE_ACCOUNT_ID
72	      ? [{ provider: 'cloudflare', model: '@cf/meta/llama-3.3-70b-instruct-fp8-fast' }] : []),
73	    { provider: 'gemini', model: 'gemini-2.5-flash-lite' },
74	    ...(process.env.DASHSCOPE_API_KEY ? [{ provider: 'qwen', model: process.env.QWEN_MODEL || 'qwen-plus' }] : []),
75	  ];
76	  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
77	    // Wall-clock budget (E-224): the gate must never blow the mint's per-build cap. Out of time -> drop cleanly.
78	    if (deadlineMs && attempt > 1 && (Date.now() - t0) > deadlineMs) {
79	      history.push({ score: 0, provider: null, deficiencies: ['gate_deadline_exceeded_after_' + (attempt - 1) + '_attempts'] });
80	      break;
81	    }
82	    const _protocol = PROTOCOLS[attempt] ? (PROTOCOLS[attempt] + '\n\n') : '';
83	    const _chain = (attempt >= 3) ? (premium_chain || _defaultPremium) : chain;
84	    let r = null;
85	    try {
86	      r = await run({
87	        role, chain: _chain, system,
88	        prompt: _protocol + prompt + (feedback ? ('\n\n' + feedback) : ''),
89	        json: true, temperature, max_tokens, lead_id, scan_id: (scan_id || '') + ':gate' + attempt,
90	      });
91	    } catch (_e) { r = null; }
92	    if (!r || !r.ok || !String(r.text || '').trim()) {
93	      history.push({ score: 0, provider: (r && r.provider) || null, deficiencies: ['provider_unavailable_or_empty'] });
94	      continue;   // chain exhausted for this attempt; a later attempt re-walks the chain
95	    }
96	    let parsed = null;
97	    const txt = String(r.text).replace(/```json|```/g, '').trim();
98	    try { parsed = JSON.parse(txt.slice(txt.indexOf('{'), txt.lastIndexOf('}') + 1)); } catch (_e) { parsed = null; }
99	    let verdict;
100	    try { verdict = rubric(parsed, txt) || { score: 0, deficiencies: ['rubric_returned_nothing'] }; }
101	    catch (e) { verdict = { score: 0, deficiencies: ['rubric_crash:' + String(e && e.message || e).slice(0, 80)] }; }
102	    const score = Math.max(0, Math.min(10, Number(verdict.score) || 0));
103	    const defs = Array.isArray(verdict.deficiencies) ? verdict.deficiencies.slice(0, 8) : [];
104	    history.push({ score, provider: (r.provider || '') + '/' + (r.model || ''), deficiencies: defs });
105	    if (score >= threshold && !verdict.hard_fail) {
106	      return { ok: true, out: parsed, score, attempts: attempt, provider: (r.provider || '') + '/' + (r.model || ''), deficiencies: [], history };
107	    }
108	    // Targeted-deficiency feedback for the next attempt (never echoes the failed answer back — that anchors it).
109	    feedback = 'YOUR PREVIOUS ANSWER SCORED ' + score + '/10 AND WAS REJECTED. Fix EXACTLY these deficiencies and return the corrected strict JSON only:\n' +
110	      defs.map((d) => '- ' + d).join('\n');
111	  }
112	  const last = history[history.length - 1] || { score: 0, deficiencies: ['no_attempts'] };
113	  return { ok: false, out: null, score: last.score, attempts: history.length, provider: last.provider || null, deficiencies: last.deficiencies, history };
114	}
115	
116	// ---- shared deterministic rubric helpers ----
117	const H = {
118	  // n points if every item in `quotes` appears verbatim (case-insensitive) in `corpus`; deficiency lists misses.
119	  anchored(quotes, corpus, pts, label) {
120	    const lc = String(corpus || '').toLowerCase();
121	    const misses = (quotes || []).filter((q) => { const s = String(q || '').toLowerCase().trim().slice(0, 60); return !(s.length >= 8 && lc.includes(s)); });
122	    return { pts: misses.length ? 0 : pts, def: misses.length ? (label + ': evidence not found verbatim on the site for: ' + misses.map((m) => '"' + String(m).slice(0, 40) + '"').join(', ')) : null };
123	  },
124	  inSet(value, set, pts, label, allowed) {
125	    const ok = set.has(String(value || '').toLowerCase());
126	    return { pts: ok ? pts : 0, def: ok ? null : (label + ' "' + String(value) + '" is not in the allowed list' + (allowed ? '. Choose ONLY from: ' + allowed : '')) };
127	  },
128	};
129	
130	module.exports = { gateLLM, H };
