153	// Two checker dialects are accepted:
154	//   a) stdout dialect: `--calibrate` prints {"checker":"...","findings":[...]} to stdout, exit 0.
155	//   b) gate-cli dialect (tools/lib/gate-cli.js): `--calibrate --json <path>` writes a findings
156	//      ARRAY to <path>, prints human text to stdout, and exits 1 when zero violations were
157	//      found. A non-zero exit is therefore NOT a runner error here: we still read the JSON
158	//      file and let this runner judge the (possibly empty) findings list.
159	// runCalibrateProcess(checkerPath, jsonOut) -> stdout from spawning the checker's --calibrate
160	// contract, having already validated its exit status against the two runner-judged states.
161	// The --calibrate contract has exactly two runner-judged statuses: 0 (checker found violations) and
162	// 1 (checker found ZERO on its fixtures - the caller then FAILs that calibration from the empty
163	// findings list). Exit 2 means the checker's OWN self-test failed: it is a broken tool and can
164	// NEVER earn a PASS, no matter what findings it managed to write. A broken self-test masked by
165	// parsed findings is the unearned-zero disease (Constitution Rule 4), so reject it unconditionally.
166	function runCalibrateProcess(checkerPath, jsonOut) {
167	  let stdout = '';
168	  let status = 0;
169	  try {
170	    stdout = execFileSync(process.execPath, [checkerPath, '--calibrate', '--json', jsonOut], {
171	      cwd: REPO_ROOT,
172	      encoding: 'utf8',
173	      timeout: 120000,
174	    });
175	  } catch (e) {
176	    // gate-cli exits 1 on zero calibration findings and 2 on a failed self-test. Keep the
177	    // stdout we got; if the checker wrote no JSON file either, the throw below reports it.
178	    stdout = (e.stdout || '') + '';
179	    status = (typeof e.status === 'number') ? e.status : 2;
180	  }
181	  if (status === 2) {
182	    throw new Error('checker self-test FAILED (exit 2): it cannot see the class it exists to catch, so its calibration result is void and cannot be masked by any parsed findings');
183	  }
184	  if (status !== 0 && status !== 1) {
185	    throw new Error('checker exited with undocumented --calibrate status ' + status + ' (expected 0 = findings, 1 = zero-findings, 2 = broken self-test)');
186	  }
187	  return stdout;
188	}
