130	// provider. Returns { ok, value?, text?, response?, record }. `record` is always populated for the
131	// attempts ledger (Part B Rule 9: log every routing decision). A structural `validate` (llm/gate.js)
132	// turns a transport success into a routing success ONLY when the response also passes the gate - a
133	// fluent-but-hallucinated answer must not win just because the socket returned 200.
134	async function callProvider(provider, task, deadlineMs, validate, log) {
135	  const t0 = Date.now();
136	  const controller = new AbortController();
137	  let raced;
138	  try {
139	    raced = await withDeadline(
140	      Promise.resolve().then(() => provider.call(task, { signal: controller.signal })),
141	      deadlineMs,
142	      () => controller.abort()
143	    );
144	  } catch (e) {
145	    // FAIL-OPEN (this call only): a throwing injected caller is a provider failure, recorded as a
146	    // typed 'threw' outcome so the chain falls OVER to the next provider. The SYSTEM stays fail-closed
147	    // because an exhausted chain returns ok:false (abstain), never a fabricated answer.
148	    raced = { timedOut: false, value: null, error: 'threw:' + String((e && e.message) || e).slice(0, 60) };
149	  }
150	  const ms = Date.now() - t0;
151	  const base = { provider: provider.name, family: provider.family, ms };
152	  if (raced.timedOut) return finalize(base, 'timeout', null, log);
153	  const interp = interpretResponse(raced.error ? { ok: false, error: raced.error } : raced.value);
154	  if (!interp.ok) return finalize(base, interp.error, null, log);
155	  if (typeof validate === 'function') return validated(base, interp, raced.value, validate, log);
156	  return { ok: true, text: interp.text, response: raced.value, record: logged(base, 'ok', log) };
157	}
158	
159	// validated(base, interp, raw, validate, log): apply the injected structural gate to a transport
160	// success. A rejection is recorded as 'gate_reject' and treated as a provider failure (fall over).
