    raced = await withDeadline(
      Promise.resolve().then(() => provider.call(task, { signal: controller.signal })),
      deadlineMs,
      () => controller.abort()
    );
  } catch (e) {
    // FAIL-OPEN (this call only): a throwing injected caller is a provider failure, recorded as a
    // typed 'threw' outcome so the chain falls OVER to the next provider. The SYSTEM stays fail-closed
    // because an exhausted chain returns ok:false (abstain), never a fabricated answer.
    raced = { timedOut: false, value: null, error: 'threw:' + String((e && e.message) || e).slice(0, 60) };
  }
  const ms = Date.now() - t0;
  const base = { provider: provider.name, family: provider.family, ms };
  if (raced.timedOut) return finalize(base, 'timeout', null, log);
  const interp = interpretResponse(raced.error ? { ok: false, error: raced.error } : raced.value);
  if (!interp.ok) return finalize(base, interp.error, null, log);
  if (typeof validate === 'function') return validated(base, interp, raced.value, validate, log);
  return { ok: true, text: interp.text, response: raced.value, record: logged(base, 'ok', log) };
